          sourceSnippet2: "BBC News — Netherlands same-sex marriage anniversary",
          source3: "Encyclopaedia Britannica",
          sourceUrl3: "https://www.britannica.com/topic/same-sex-marriage",
          sourceSnippet3: "Encyclopaedia Britannica — Same-sex marriage, Netherlands first"
